def _term_stem(t: str) -> str:
    """Crude, dependency-free stem so near-duplicates (regulation/regulatory, skill/skills) collapse
    to ONE title term. Not linguistically perfect — just enough to avoid 'Regulation Regulatory'."""
    t = str(t).lower().strip()
    for suf in ("ational", "ization", "isation", "ations", "atory", "ities", "ing", "ion", "ers",
                "ies", "es", "s"):
        if len(t) - len(suf) >= 4 and t.endswith(suf):
            return t[: len(t) - len(suf)]
    return t


def _titlecase_terms(terms: list[str]) -> str:
    """Deterministic, human-ish section title from a cluster's top distinctive terms, with
    near-duplicate stems collapsed and the first 2-3 distinct terms joined readably."""
    seen: list[str] = []
    seen_stems: set[str] = set()
    for t in terms:
        t = str(t).strip()
        st = _term_stem(t)
        if t and st not in seen_stems:
            seen.append(t.capitalize())
            seen_stems.add(st)
        if len(seen) >= 3:
            break
    if not seen:
        return "Additional Corpus Theme"
    if len(seen) == 1:
        return seen[0]
    return ", ".join(seen[:-1]) + " and " + seen[-1]

